create temp table failure_results as select n,public.creator_publishing_requeue_retry_exhausted_scheduler_event(task21_retry_recovery_test.uuid(5,n),'failure_key_'||lpad(n::text,4,'0'),'MANUAL_RETRY_APPROVED') result from generate_series(10,27)n union all select n,public.creator_publishing_requeue_retry_exhausted_scheduler_event(task21_retry_recovery_test.uuid(5,n),'failure_key_'||lpad(n::text,4,'0'),'MANUAL_RETRY_APPROVED') from generate_series(30,38)n;
