with current_non_event as (select 'account' t,id::text k,to_jsonb(x) v from public.creator_platform_accounts x where id::text like '21300000-%' union all select 'package',id::text,to_jsonb(x) from public.creator_publishing_content_packages x where id::text like '21300000-%' union all select 'plan',id::text,to_jsonb(x) from public.creator_publishing_plans x where id::text like '21300000-%' union all select 'job',id::text,to_jsonb(x) from public.creator_publishing_platform_jobs x where id::text like '21300000-%' union all select 'queue',id::text,to_jsonb(x) from public.creator_publishing_queue_tasks x where id::text like '21300000-%' union all select 'capability',platform,to_jsonb(x) from public.creator_publishing_platform_capabilities x union all select 'generation',id::text,to_jsonb(x) from public.generations x),delta as ((select * from current_non_event except select * from non_event_before) union all(select * from non_event_before except select * from current_non_event)) select task21_retry_recovery_test.assert(not exists(select 1 from delta),'no unrelated mutation');
