select task21_retry_recovery_test.assert(not exists(select 1 from public.task21_recovery_pre_data_snapshot s join public.creator_publishing_scheduler_idempotency i on s.entity_type='idempotency' and s.entity_id=i.creator_id::text||':'||i.action_type||':'||i.idempotency_key where s.row_data is distinct from to_jsonb(i)),'historical scheduler idempotency rows unchanged');
